mapper.update:
UPDATE media.upload_intents
SET status = 'COMPLETED', media_file_id = #{mediaFileId}, completed_at = #{completedAt}
WHERE id = #{id} AND status = 'PENDING'

mapper.select:
SELECT id, owner_user_id, object_key, status, media_file_id, expires_at, created_at, completed_at
FROM media.upload_intents
WHERE status IN ('PENDING', 'PURGING') AND expires_at <= #{now}
ORDER BY expires_at
LIMIT #{limit}
